var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"그레모리 씨, 저 당신을 좋아합니다!","JPN":"グレモリーさん！　私、あなたのことが好きです！","ENG":"Gremory, I love you!","TWN":"葛茉莉小姐，我喜歡你！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 그래?","JPN":"あら、そう？","ENG":"Oh, is that so?","TWN":"哎呀，真的嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그레모리 씨의 가게에 손님이 찾아오는 데엔 여러 이유가 있습니다.","JPN":"グレモリーさんのお店にお客様がやってくる理由は色々です。","ENG":"There are many reasons why customers come to Gremory's bar.","TWN":"來到葛茉莉酒吧的客人，各有各的理由。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"순수하게 칵테일의 향과 맛을 즐기러 오는 손님도, 귀여운 모모를 보고 싶어서 오는 손님도 계시지만…","JPN":"単純にカクテルの香りと味を楽しむために来るお客様も、可愛いモモと会うために来るお客様もいるんですけど……","ENG":"Some come just to enjoy the cocktails, while others come to see Momo's cuteness...","TWN":"有人純粹是為了雞尾酒的香氣與口感而來，也有人是想看看可愛的莫莫……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"매력적인 그레모리 씨의 관심을 얻으려고 찾아오는 손님도 계세요.","JPN":"魅力的なグレモリーさんの目を引くためにやってくるお客様もいるんです。","ENG":"However, some people come to get the attention of the charming Gremory.","TWN":"但也有客人，是為了得到迷人的葛茉莉小姐的關注而來。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"지금까진 다들 내기를 한판하고 나면 포기하게 되지만요.","JPN":"今まではみんな賭けをしたら諦めるようになるんですけど。","ENG":"But most of them give up after losing a challenge.","TWN":"只不過到目前為止，大家在打完一場賭之後就都放棄了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"…세 잔이라고요?","JPN":"……3杯？","ENG":"...Three drinks?","TWN":"……三杯嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"응, 네가 술을 세 잔 마시고도 맨정신으로 버틸 수 있으면 내기에 이기는 거야.","JPN":"うん、アナタがお酒を3杯飲んでも酔っぱらっていないと、賭けで勝利するの。","ENG":"Yes, if you can still be sober after three drinks, then you win.","TWN":"嗯，只要你喝三杯還能保持清醒，就算你贏。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"정말이죠?! 그렇게만 하면 절 만나주시는 겁니까?","JPN":"本当ですよね！？　そしたら私と付き合ってくれるんですか？","ENG":"Really?! Then you'll go out with me?","TWN":"真的嗎？！只要那樣，你就願意跟我見面？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"고작 만나주는 정도로 만족하겠어? 해내기만 한다면 소원 하나 들어 줄게.","JPN":"付き合ってあげるだけで満足できる？　成功したら願いを1つ叶えてあげるわ。","ENG":"Will you be satisfied with just a date? If you win, I'll grant you a wish.","TWN":"只要見面你就滿足了？只要你辦得到，我都能幫你實現任何願望。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"무슨 소원이든 말이야.","JPN":"どんな願いでもね。","ENG":"Any wish your heart desires.","TWN":"不管是什麼願望哦。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"하겠습니다! 부디 하게 해주세요!","JPN":"やります！　どうかやらせてください！","ENG":"I'll do it! Please let me do it!","TWN":"我願意！請務必讓我試試看！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"들었지, 니콜 양? 데몬 레이디 세 잔 부탁해.","JPN":"聞いたわね、ニコルちゃん？　デーモンレディーを3杯お願い。","ENG":"Did you hear that, Nicole? Please prepare three glasses of Demon Lady.","TWN":"聽到了吧，妮可小姐？三杯惡魔淑女，拜託你了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네, 알겠습니다!","JPN":"はい、わかりました！","ENG":"Coming right up!","TWN":"是，我知道了！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"흐음, 향이 좋은데요? 이게 그레모리 씨가 평소 즐겨 마시는 칵테일이로군요.","JPN":"ふーん、いい香りですね。これがグレモリーさんがいつも飲んでいるカクテルですか？","ENG":"Hmm, it smells nice. So this is Gremory's favorite cocktail.","TWN":"嗯，香氣真好。原來這就是葛茉莉小姐平常喝的酒。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…조심하세요, 손님. 지금까지 데몬 레이디를 한 잔 이상 마시고 버틴 손님은 아무도 없었거든요.","JPN":"……気をつけてくださいね、お客様。今までデーモンレディーを1杯以上飲んで酔わなかったお客様は1人もいなかったんです。","ENG":"...Be careful, sir. No one has ever been able to finish more than one glass.","TWN":"……請小心，客人。到目前為止，沒有任何人能撐過第二杯惡魔淑女。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"하하, 괜찮아요. 난 술에 강하니까. 독해봤자 작은 잔에 담긴 칵테일일 뿐이죠.","JPN":"はは、大丈夫ですよ。私お酒には強いんで。これくらい小さなグラスの分では全然酔いませんから。","ENG":"Haha! Don't worry. I know how to hold my liquor. Plus, how strong can a cocktail be?","TWN":"哈哈，沒問題的。我酒量很好，再烈也不過是一小杯雞尾酒。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하아, 전 경고 드렸어요.","JPN":"はあ、私は警告しましたよ。","ENG":"*Sigh* You've been warned.","TWN":"唉，我可是警告過你了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"으… 음? 여긴 어디지?","JPN":"う……うん？　ここはどこだ？","ENG":"M-mm...? Where am I?","TWN":"呃……嗯？這裡是哪裡？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"손님아, 정신이 드느냐?","JPN":"客よ、目が覚めたか？","ENG":"Hey, you're finally awake.","TWN":"客人，你醒了嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"뿔 달린… 악마…?","JPN":"角の生えた……悪魔……？","ENG":"A devil... with horns...?","TWN":"長角的……惡魔……？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"정신이 든다면 17 곱하기 5의 정답을 말해보거라.","JPN":"目が覚めたなら、17かける5に答えるがよい。","ENG":"If you've come to your senses, tell me what 17 times 5 is.","TWN":"既然醒了，你說說看17乘以5等於多少。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"으음… 85…?","JPN":"うーん……85……？","ENG":"Um... 85...?","TWN":"嗯……85……？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"훌륭하도다. 정신이 돌아온 것을 칭찬하마.","JPN":"見事だ。意識を取り戻したことを褒めてやろう。","ENG":"Excellent. I praise you for coming to your senses.","TWN":"很好，恭喜你恢復意識了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗! 모모! 숙제 문제 풀 때 손님한테 물어보지 말랬죠?","JPN":"あっ！　モモ！　宿題はお客様に聞かないでって言ったでしょう！","ENG":"Huh?! Momo! Didn't I tell you not to ask customers to help with your homework?","TWN":"啊！莫莫！寫作業的時候不可以問客人啦！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"니콜…? 제가 왜 여기에 누워있는 거죠?","JPN":"ニコル……？　どうして私がここで寝てるんですか？","ENG":"Nicole...? Why am I lying down here?","TWN":"妮可……？我怎麼會躺在這裡？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"첫 잔은 원샷이라면서 드시는 순간 쓰러지셨어요.","JPN":"最初の1杯は一気飲みだって飲んだ瞬間、倒れたんです。","ENG":"You fainted after shouting, \\"Bottoms up!\\" and guzzling down the first glass.","TWN":"你一口氣喝完第一杯後就倒下了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"…그렇군요. 내 사랑은 고작 한 잔의 술 앞에 져버린 건가.","JPN":"……そうなんですか。私の恋はたかが1杯のお酒の前で負けてしまったのか。","ENG":"...I see. So my love's been lost to just one drink.","TWN":"……原來如此。我的愛情竟然輸給了一杯酒。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"너무 상심하지 마세요. 기회는 다음 번에도 있잖아요?","JPN":"あまりガッカリしないでくださいよ。チャンスはまたあるんですから。","ENG":"Don't be too upset. There's always next time, right?","TWN":"別太難過了，下次還有機會啊？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};